import machine
import time
from umqtt.simple import MQTTClient

# Define WiFi credentials
SSID = 'your_wifi_ssid'
PASSWORD = 'your_wifi_password'

# Define MQTT broker details
BROKER_IP = 'mqtt_broker_ip'
CLIENT_ID = 'esp32_client'

# Function to connect to WiFi
def connect_wifi():
    sta_if = network.WLAN(network.STA_IF)
    if not sta_if.isconnected():
        print('Connecting to WiFi...')
        sta_if.active(True)
        sta_if.connect(SSID, PASSWORD)
        while not sta_if.isconnected():
            pass
    print('WiFi connected:', sta_if.ifconfig())

# Function to read temperature from DHT22 sensor
def read_temperature(sensor_pin):
    import dht
    sensor = dht.DHT22(machine.Pin(sensor_pin))
    sensor.measure()
    return sensor.temperature()

# Initialize MQTT client
client = MQTTClient(CLIENT_ID, BROKER_IP)

try:
    # Connect to WiFi
    connect_wifi()

    # Connect to MQTT broker
    client.connect()
    print('Connected to MQTT broker')

    while True:
        # Read temperature
        temp = read_temperature(4)  # Assuming DHT22 is connected to GPIO pin 4

        # Publish temperature to topic
        client.publish(b'sensors/temp', str(temp))
        print('Published temperature:', temp)

        # Wait for 10 seconds before next reading
        time.sleep(10)

except Exception as e:
    print('Error:', e)
finally:
    client.disconnect()